11		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/dataplane"
12		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/file"
13	)
14	
15	const (
16		integrationID = "ngf"
17	)
18	
19	type fileToCopy struct {
20		destDirName string
21		srcFileName string
22	}
23	
24	type initializeConfig struct {
25		fileManager   file.OSFileManager
26		fileGenerator config.Generator
27		logger        logr.Logger
28		podUID        string
29		clusterUID    string
30		copy          []fileToCopy
31		plus          bool
32	}
33	
34	func initialize(cfg initializeConfig) error {
35		for _, f := range cfg.copy {
36			if err := copyFile(cfg.fileManager, f.srcFileName, f.destDirName); err != nil {
37				return err
38			}
39		}
40	
41		if !cfg.plus {
42			cfg.logger.Info("Finished initializing configuration")
43			return nil
44		}
45	
46		depCtx := dataplane.DeploymentContext{
47			InstallationID: &cfg.podUID,
48			ClusterID:      &cfg.clusterUID,
49			Integration:    integrationID,
50		}
51	
52		depCtxFile, err := cfg.fileGenerator.GenerateDeploymentContext(depCtx)
53		if err != nil {
54			return fmt.Errorf("failed to generate deployment context file: %w", err)
55		}
56	
57		if err := file.Write(cfg.fileManager, file.Convert(depCtxFile)); err != nil {
58			return fmt.Errorf("failed to write deployment context file: %w", err)
59		}
60	
61		cfg.logger.Info("Finished initializing configuration")
62	
63		return nil
64	}
65	
66	func copyFile(osFileManager file.OSFileManager, src, dest string) error {
67		srcFile, err := osFileManager.Open(src)
68		if err != nil {
69			return fmt.Errorf("error opening source file: %w", err)
70		}
71		defer srcFile.Close()
72	
73		destFile, err := osFileManager.Create(filepath.Join(dest, filepath.Base(src)))
74		if err != nil {
75			return fmt.Errorf("error creating destination file: %w", err)
76		}
77		defer destFile.Close()
78	
79		if err := osFileManager.Copy(destFile, srcFile); err != nil {
80			return fmt.Errorf("error copying file contents: %w", err)
81		}
82	
83		if err := osFileManager.Chmod(destFile, os.FileMode(file.RegularFileModeInt)); err != nil {
84			return fmt.Errorf("error setting file permissions: %w", err)
85		}
86	
87		return nil
88	}
