3	import (
4		"context"
5		"crypto/rand"
6		"crypto/rsa"
7		"crypto/sha1" //nolint:gosec // using sha1 in this case is fine
8		"crypto/tls"
9		"crypto/x509"
10		"crypto/x509/pkix"
11		"encoding/pem"
12		"fmt"
13		"math/big"
14		"reflect"
15		"time"
16	
17		corev1 "k8s.io/api/core/v1"
18		apierrors "k8s.io/apimachinery/pkg/api/errors"
19		metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
20		"sigs.k8s.io/controller-runtime/pkg/client"
21		ctlrZap "sigs.k8s.io/controller-runtime/pkg/log/zap"
22	
23		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/graph/shared/secrets"
24	)
25	
26	const (
27		expiry        = 365 * 3 * 24 * time.Hour // 3 years
28		defaultDomain = "cluster.local"
29	)
30	
31	var subject = pkix.Name{
32		CommonName:         "nginx-gateway",
33		Country:            []string{"US"},
34		Locality:           []string{"SEA"},
35		Organization:       []string{"F5"},
36		OrganizationalUnit: []string{"NGINX"},
37	}
38	
39	type certificateConfig struct {
40		caCertificate     []byte
41		serverCertificate []byte
42		serverKey         []byte
43		clientCertificate []byte
44		clientKey         []byte
45	}
46	
47	// generateCertificates creates a CA, server, and client certificates and keys.
48	func generateCertificates(service, namespace, clientDNSDomain, serverTLSDomain string) (*certificateConfig, error) {
49		caCertPEM, caKeyPEM, err := generateCA()
50		if err != nil {
51			return nil, fmt.Errorf("error generating CA: %w", err)
52		}
53	
54		caKeyPair, err := tls.X509KeyPair(caCertPEM, caKeyPEM)
55		if err != nil {
56			return nil, err
57		}
58	
59		serverCert, serverKey, err := generateCert(caKeyPair, serverDNSNames(service, namespace, serverTLSDomain))
60		if err != nil {
61			return nil, fmt.Errorf("error generating server cert: %w", err)
62		}
63	
64		clientCert, clientKey, err := generateCert(caKeyPair, clientDNSNames(clientDNSDomain))
65		if err != nil {
66			return nil, fmt.Errorf("error generating client cert: %w", err)
67		}
68	
69		return &certificateConfig{
70			caCertificate:     caCertPEM,
71			serverCertificate: serverCert,
72			serverKey:         serverKey,
73			clientCertificate: clientCert,
74			clientKey:         clientKey,
75		}, nil
76	}
77	
78	func generateCA() ([]byte, []byte, error) {
79		caKey, err := rsa.GenerateKey(rand.Reader, 2048)
80		if err != nil {
81			return nil, nil, err
82		}
83	
84		ca := &x509.Certificate{
85			Subject:               subject,
86			NotBefore:             time.Now(),
87			NotAfter:              time.Now().Add(expiry),
88			SubjectKeyId:          subjectKeyID(caKey.N),
89			KeyUsage:              x509.KeyUsageCertSign | x509.KeyUsageDigitalSignature | x509.KeyUsageKeyEncipherment,
90			IsCA:                  true,
91			BasicConstraintsValid: true,
92		}
93	
94		caCertBytes, err := x509.CreateCertificate(rand.Reader, ca, ca, &caKey.PublicKey, caKey)
95		if err != nil {
96			return nil, nil, err
97		}
98	
99		caCertPEM := pem.EncodeToMemory(&pem.Block{
100			Type:  "CERTIFICATE",
101			Bytes: caCertBytes,
102		})
103	
104		caKeyPEM := pem.EncodeToMemory(&pem.Block{
105			Type:  "RSA PRIVATE KEY",
106			Bytes: x509.MarshalPKCS1PrivateKey(caKey),
107		})
108	
109		return caCertPEM, caKeyPEM, nil
110	}
111	
112	func generateCert(caKeyPair tls.Certificate, dnsNames []string) ([]byte, []byte, error) {
113		key, err := rsa.GenerateKey(rand.Reader, 2048)
114		if err != nil {
115			return nil, nil, err
116		}
117	
118		cert := &x509.Certificate{
119			Subject:      subject,
120			NotBefore:    time.Now(),
121			NotAfter:     time.Now().Add(expiry),
122			SubjectKeyId: subjectKeyID(key.N),
123			KeyUsage:     x509.KeyUsageDigitalSignature | x509.KeyUsageKeyEncipherment,
124			DNSNames:     dnsNames,
125		}
126	
127		caCert, err := x509.ParseCertificate(caKeyPair.Certificate[0])
128		if err != nil {
129			return nil, nil, err
130		}
131	
132		certBytes, err := x509.CreateCertificate(rand.Reader, cert, caCert, &key.PublicKey, caKeyPair.PrivateKey)
133		if err != nil {
134			return nil, nil, err
135		}
136	
137		certPEM := pem.EncodeToMemory(&pem.Block{
138			Type:  "CERTIFICATE",
139			Bytes: certBytes,
140		})
141	
142		keyPEM := pem.EncodeToMemory(&pem.Block{
143			Type:  "RSA PRIVATE KEY",
144			Bytes: x509.MarshalPKCS1PrivateKey(key),
145		})
146	
147		return certPEM, keyPEM, nil
148	}
149	
150	// subjectKeyID generates the SubjectKeyID using the modulus of the private key.
151	func subjectKeyID(n *big.Int) []byte {
152		h := sha1.New() //nolint:gosec // using sha1 in this case is fine
153		h.Write(n.Bytes())
154		return h.Sum(nil)
155	}
156	
157	func serverDNSNames(service, namespace, serverTLSDomain string) []string {
158		return []string{
159			fmt.Sprintf("%s.%s.%s", service, namespace, serverTLSDomain),
160		}
161	}
162	
163	func clientDNSNames(dnsDomain string) []string {
164		return []string{
165			fmt.Sprintf("*.%s", dnsDomain),
166		}
167	}
168	
169	func createSecrets(
170		ctx context.Context,
171		k8sClient client.Client,
172		certConfig *certificateConfig,
173		serverSecretName,
174		clientSecretName,
175		namespace string,
176		overwrite bool,
177	) error {
178		serverSecret := corev1.Secret{
179			ObjectMeta: metav1.ObjectMeta{
180				Name:      serverSecretName,
181				Namespace: namespace,
182			},
183			Type: corev1.SecretTypeTLS,
184			Data: map[string][]byte{
185				secrets.CAKey:      certConfig.caCertificate,
186				secrets.TLSCertKey: certConfig.serverCertificate,
187				secrets.TLSKeyKey:  certConfig.serverKey,
188			},
189		}
190	
191		clientSecret := corev1.Secret{
192			ObjectMeta: metav1.ObjectMeta{
193				Name:      clientSecretName,
194				Namespace: namespace,
195			},
196			Type: corev1.SecretTypeTLS,
197			Data: map[string][]byte{
198				secrets.CAKey:      certConfig.caCertificate,
199				secrets.TLSCertKey: certConfig.clientCertificate,
200				secrets.TLSKeyKey:  certConfig.clientKey,
201			},
202		}
203	
204		logger := ctlrZap.New().WithName("cert-generator")
205		for _, secret := range []corev1.Secret{serverSecret, clientSecret} {
206			key := client.ObjectKeyFromObject(&secret)
207			currentSecret := &corev1.Secret{}
208	
209			if err := k8sClient.Get(ctx, key, currentSecret); err != nil {
210				if apierrors.IsNotFound(err) {
211					if err := k8sClient.Create(ctx, &secret); err != nil {
212						return fmt.Errorf("error creating secret %v: %w", key, err)
213					}
214				} else {
215					return fmt.Errorf("error getting secret %v: %w", key, err)
216				}
217			} else {
218				if !overwrite {
219					logger.Info("Skipping updating Secret. Must be updated manually or by another source.", "name", key)
220					continue
221				}
222	
223				if !reflect.DeepEqual(secret.Data, currentSecret.Data) {
224					if err := k8sClient.Update(ctx, &secret); err != nil {
225						return fmt.Errorf("error updating secret %v: %w", key, err)
226					}
227				}
228			}
229		}
230	
231		return nil
232	}
