3	import (
4		"crypto/tls"
5		"errors"
6		"fmt"
7		"io"
8		"net"
9		"net/http"
10		"strings"
11		"time"
12	
13		corev3 "github.com/envoyproxy/go-control-plane/envoy/config/core/v3"
14		extprocv3 "github.com/envoyproxy/go-control-plane/envoy/service/ext_proc/v3"
15		"github.com/go-logr/logr"
16		"google.golang.org/grpc"
17		"google.golang.org/grpc/credentials"
18		"google.golang.org/grpc/credentials/insecure"
19		eppMetadata "sigs.k8s.io/gateway-api-inference-extension/pkg/epp/metadata"
20	
21		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/types"
22	)
23	
24	// extProcClientFactory creates a new ExternalProcessorClient and returns a close function.
25	type extProcClientFactory func(target string) (extprocv3.ExternalProcessorClient, func() error, error)
26	
27	// endpointPickerServer starts an HTTP server on the given port with the provided handler.
28	func endpointPickerServer(handler http.Handler) error {
29		server := &http.Server{
30			Addr:              fmt.Sprintf("127.0.0.1:%d", types.GoShimPort),
31			Handler:           handler,
32			ReadHeaderTimeout: 10 * time.Second,
33		}
34		return server.ListenAndServe()
35	}
36	
37	// realExtProcClientFactory returns a factory that creates a new gRPC connection and client per request.
38	func realExtProcClientFactory(disableTLS, tlsSkipVerify bool) extProcClientFactory {
39		return func(target string) (extprocv3.ExternalProcessorClient, func() error, error) {
40			var opts []grpc.DialOption
41	
42			if disableTLS {
43				opts = append(opts, grpc.WithTransportCredentials(insecure.NewCredentials()))
44			} else {
45				creds := credentials.NewTLS(&tls.Config{
46					InsecureSkipVerify: tlsSkipVerify, //nolint:gosec
47				})
48				opts = append(opts, grpc.WithTransportCredentials(creds))
49			}
50	
51			conn, err := grpc.NewClient(target, opts...)
52			if err != nil {
53				return nil, nil, err
54			}
55			client := extprocv3.NewExternalProcessorClient(conn)
56			return client, conn.Close, nil
57		}
58	}
59	
60	// createEndpointPickerHandler returns an http.Handler that forwards requests to the EndpointPicker.
61	func createEndpointPickerHandler(factory extProcClientFactory, logger logr.Logger) http.Handler {
62		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
63			host := r.Header.Get(types.EPPEndpointHostHeader)
64			port := r.Header.Get(types.EPPEndpointPortHeader)
65			if host == "" || port == "" {
66				msg := fmt.Sprintf(
67					"missing at least one of required headers: %s and %s",
68					types.EPPEndpointHostHeader,
69					types.EPPEndpointPortHeader,
70				)
71				logger.Error(errors.New(msg), "error contacting EndpointPicker")
72				http.Error(w, msg, http.StatusBadRequest)
73				return
74			}
75	
76			target := net.JoinHostPort(host, port)
77			logger.Info("Getting inference workload endpoint from EndpointPicker", "endpointPicker", target)
78	
79			client, closeConn, err := factory(target)
80			if err != nil {
81				logger.Error(err, "error creating gRPC client")
82				http.Error(w, fmt.Sprintf("error creating gRPC client: %v", err), http.StatusInternalServerError)
83				return
84			}
85			defer func() {
86				if err := closeConn(); err != nil {
87					logger.Error(err, "error closing gRPC connection")
88				}
89			}()
90	
91			stream, err := client.Process(r.Context())
92			if err != nil {
93				logger.Error(err, "error opening ext_proc stream")
94				http.Error(w, fmt.Sprintf("error opening ext_proc stream: %v", err), http.StatusBadGateway)
95				return
96			}
97	
98			if code, err := sendRequest(stream, r); err != nil {
99				logger.Error(err, "error sending request")
100				http.Error(w, err.Error(), code)
101				return
102			}
103	
104			// Receive response and extract header
105			for {
106				resp, err := stream.Recv()
107				if errors.Is(err, io.EOF) {
108					break // End of stream
109				} else if err != nil {
110					logger.Error(err, "error receiving from ext_proc")
111					http.Error(w, fmt.Sprintf("error receiving from ext_proc: %v", err), http.StatusBadGateway)
112					return
113				}
114	
115				if ir := resp.GetImmediateResponse(); ir != nil {
116					code := int(ir.GetStatus().GetCode())
117					body := ir.GetBody()
118					logger.Error(fmt.Errorf("code: %d, body: %s", code, body), "received immediate response")
119					http.Error(w, string(body), code)
120					return
121				}
122	
123				headers := resp.GetRequestHeaders().GetResponse().GetHeaderMutation().GetSetHeaders()
124				for _, h := range headers {
125					if h.GetHeader().GetKey() == eppMetadata.DestinationEndpointKey {
126						endpoint := string(h.GetHeader().GetRawValue())
127						w.Header().Set(h.GetHeader().GetKey(), endpoint)
128						logger.Info("Found endpoint", "endpoint", endpoint)
129					}
130				}
131			}
132			w.WriteHeader(http.StatusOK)
133		})
134	}
135	
136	func sendRequest(stream extprocv3.ExternalProcessor_ProcessClient, r *http.Request) (int, error) {
137		if err := stream.Send(buildHeaderRequest(r)); err != nil {
138			return http.StatusBadGateway, fmt.Errorf("error sending headers: %w", err)
139		}
140	
141		bodyReq, err := buildBodyRequest(r)
142		if err != nil {
143			return http.StatusInternalServerError, fmt.Errorf("error building body request: %w", err)
144		}
145	
146		if err := stream.Send(bodyReq); err != nil {
147			return http.StatusBadGateway, fmt.Errorf("error sending body: %w", err)
148		}
149	
150		if err := stream.CloseSend(); err != nil {
151			return http.StatusInternalServerError, fmt.Errorf("error closing stream: %w", err)
152		}
153	
154		return 0, nil
155	}
156	
157	func buildHeaderRequest(r *http.Request) *extprocv3.ProcessingRequest {
158		headerList := make([]*corev3.HeaderValue, 0, len(r.Header))
159		headerMap := &corev3.HeaderMap{
160			Headers: headerList,
161		}
162	
163		for key, values := range r.Header {
164			for _, value := range values {
165				// Normalize header keys to lowercase for case-insensitive matching.
166				// This addresses the mismatch between Go's default HTTP header normalization (Title-Case)
167				// and EPP's expectation of lowercase header keys. Additionally, HTTP/2 — which gRPC uses —
168				// requires all header field names to be lowercase as specified in RFC 7540, Section 8.1.2:
169				// https://datatracker.ietf.org/doc/html/rfc7540#section-8.1.2
170				normalizedKey := strings.ToLower(key)
171	
172				headerMap.Headers = append(headerMap.Headers, &corev3.HeaderValue{
173					Key:   normalizedKey,
174					Value: value,
175				})
176			}
177		}
178	
179		return &extprocv3.ProcessingRequest{
180			Request: &extprocv3.ProcessingRequest_RequestHeaders{
181				RequestHeaders: &extprocv3.HttpHeaders{
182					Headers:     headerMap,
183					EndOfStream: false,
184				},
185			},
186		}
187	}
188	
189	func buildBodyRequest(r *http.Request) (*extprocv3.ProcessingRequest, error) {
190		if r.ContentLength == 0 {
191			return nil, errors.New("request body is empty")
192		}
193	
194		body, err := io.ReadAll(r.Body)
195		if err != nil {
196			return nil, fmt.Errorf("error reading request body: %w", err)
197		}
198	
199		return &extprocv3.ProcessingRequest{
200			Request: &extprocv3.ProcessingRequest_RequestBody{
201				RequestBody: &extprocv3.HttpBody{
202					Body:        body,
203					EndOfStream: true,
204				},
205			},
206		}, nil
207	}
