137	func validateEndpointOptionalPort(value string) error {
138		if len(value) == 0 {
139			return errors.New("must be set")
140		}
141	
142		host, port, err := splitHostPort(value)
143		if err != nil {
144			return err
145		}
146	
147		if port != "" {
148			if err := validatePortString(port); err != nil {
149				return err
150			}
151		}
152	
153		if err := validateIP(host); err == nil {
154			return nil
155		}
156	
157		if errs := validation.IsDNS1123Subdomain(host); len(errs) == 0 {
158			return nil
159		}
160	
161		// we don't know if the user intended to use a hostname or an IP address,
162		// so we return a generic error message
163		return fmt.Errorf("%q must be in the format [http://|https://]<host>[:<port>]", value)
164	}
