166	// splitHostPort extracts the host and optional port from an endpoint value that may include an http/https scheme.
167	// It uses net/url for scheme-prefixed values to correctly handle bracketed IPv6 addresses.
168	func splitHostPort(value string) (host, port string, err error) {
169		if strings.Contains(value, "://") {
170			u, parseErr := url.Parse(value)
171			if parseErr != nil {
172				return "", "", fmt.Errorf("invalid URL %q: %w", value, parseErr)
173			}
174			if u.Scheme != "http" && u.Scheme != "https" {
175				return "", "", fmt.Errorf("unsupported scheme %q: must be http or https", u.Scheme)
176			}
177			if u.Path != "" && u.Path != "/" {
178				return "", "", fmt.Errorf("invalid URL %q: path is not allowed", value)
179			}
180			if u.RawQuery != "" {
181				return "", "", fmt.Errorf("invalid URL %q: query is not allowed", value)
182			}
183			if u.Fragment != "" {
184				return "", "", fmt.Errorf("invalid URL %q: fragment is not allowed", value)
185			}
186			return u.Hostname(), u.Port(), nil
187		}
188	
189		// net.SplitHostPort requires a port; when the value has no port, it returns a "missing port" error.
190		// We treat that as valid (port is optional) and return the original value as host.
191		host, port, splitErr := net.SplitHostPort(value)
192		if splitErr != nil {
193			if strings.Contains(splitErr.Error(), "missing port") || strings.Contains(splitErr.Error(), "too many colons") {
194				return value, "", nil
195			}
196			return "", "", fmt.Errorf("error splitting %q into host and port: %w", value, splitErr)
197		}
198	
199		return host, port, nil
200	}
