202	func validatePortString(port string) error {
203		portVal, err := strconv.ParseInt(port, 10, 16)
204		if err != nil {
205			return fmt.Errorf("port must be a valid number: %w", err)
206		}
207		if portVal < 1 || portVal > 65535 {
208			return fmt.Errorf("port outside of valid port range [1 - 65535]: %v", port)
209		}
210		return nil
211	}
