213	func validateURL(value string) error {
214		if len(value) == 0 {
215			return errors.New("must be set")
216		}
217	
218		parsedURL, err := url.ParseRequestURI(value)
219		if err != nil {
220			return fmt.Errorf("invalid URL: %w", err)
221		}
222	
223		if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
224			return fmt.Errorf("unsupported URL scheme %q: must be http or https", parsedURL.Scheme)
225		}
226	
227		if parsedURL.Host == "" {
228			return errors.New("URL host must be set")
229		}
230	
231		return nil
232	}
