234	// validatePort makes sure a given port is inside the valid port range for its usage.
235	func validatePort(port int) error {
236		if port < 1024 || port > 65535 {
237			return fmt.Errorf("port outside of valid port range [1024 - 65535]: %v", port)
238		}
239		return nil
240	}
241	
242	// validateAnyPort makes sure a given port is inside the valid range for all ports.
243	// This includes protected ports (1-1023) and unprivileged ports (1024-65535).
244	func validateAnyPort(port int) error {
245		if port < 1 || port > 65535 {
246			return fmt.Errorf("port outside of valid port range [1 - 65535]: %v", port)
247		}
248		return nil
249	}
