265	// validateCopyArgs ensures that arguments to the initialize command are set.
266	func validateCopyArgs(srcFiles []string, destDirs []string) error {
267		if len(srcFiles) != len(destDirs) {
268			return errors.New("source and destination must have the same number of elements")
269		}
270		if len(srcFiles) == 0 {
271			return errors.New("source must not be empty")
272		}
273		if len(destDirs) == 0 {
274			return errors.New("destination must not be empty")
275		}
276	
277		return nil
278	}
