42	func (v *stringSliceValidatingValue) String() string {
43		b := &bytes.Buffer{}
44		w := csv.NewWriter(b)
45		err := w.Write(v.values)
46		if err != nil {
47			return ""
48		}
49	
50		w.Flush()
51		str := strings.TrimSuffix(b.String(), "\n")
52		return "[" + str + "]"
53	}
54	
55	func (v *stringSliceValidatingValue) Set(param string) error {
56		params := strings.Split(param, ",")
57		for i, val := range params {
58			val = strings.TrimSpace(val)
59			if err := v.validator(val); err != nil {
60				return err
61			}
62			params[i] = val
63		}
64	
65		if !v.changed {
66			v.values = params
67		} else {
68			v.values = append(v.values, params...)
69		}
70		v.changed = true
71	
72		return nil
73	}
74	
75	func (v *stringSliceValidatingValue) Type() string {
76		return "stringSlice"
77	}
